import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon, Badge, Avatar } from 'decantr/components';

code.example:
function TenantCard({ tenant }) {
  const { div, span, p, a } = tags;
  const statusColor = tenant.paymentStatus === 'current' ? 'success' : tenant.paymentStatus === 'pending' ? 'warning' : 'danger';
  const daysUntilLeaseEnd = Math.ceil((new Date(tenant.leaseEnd) - new Date()) / (1000 * 60 * 60 * 24));
  const leaseWarning = daysUntilLeaseEnd <= 60 && daysUntilLeaseEnd > 0;

  return div({ class: css('estate-card _p4') },
    div({ class: css('_flex _gap4 _mb4') },
      Avatar({ src: tenant.avatar, alt: tenant.name, size: 'lg', fallback: tenant.name.charAt(0) }),
      div({ class: css('_flex1') },
        div({ class: css('_flex _jcsb _aic _mb1') },
          span({ class: css('_heading5') }, tenant.name),
          Badge({ variant: statusColor }, tenant.paymentStatus)
        ),
        div({ class: css('_flex _col _gap1 _textsm _fgmuted') },
          a({ href: `tel:${tenant.phone}`, class: css('_flex _aic _gap1 _hoverFg') }, icon('phone', { size: '14' }), tenant.phone),
          a({ href: `mailto:${tenant.email}`, class: css('_flex _aic _gap1 _hoverFg') }, icon('mail', { size: '14' }), tenant.email)
        )
      )
    ),
    div({ class: css('_pt4 _borderT _grid _cols2 _gap4') },
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Property / Unit'),
        link({ href: `/properties/${tenant.propertyId}/units/${tenant.unitId}`, class: css('_textsm _font500 _hoverUnderline') },
          `${tenant.propertyName} - Unit ${tenant.unitNumber}`
        )
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Monthly Rent'),
        span({ class: css('_textsm _font500') }, `$${tenant.rent.toLocaleString()}`)
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Lease Start'),
        span({ class: css('_textsm') }, tenant.leaseStart)
      ),
      div({},
        span({ class: css('_textxs _fgmuted _block') }, 'Lease End'),
        span({ class: css(`_textsm ${leaseWarning ? '_fgwarning' : ''}`) },
          tenant.leaseEnd,
          leaseWarning ? ` (${daysUntilLeaseEnd} days)` : ''
        )
      )
    ),
    div({ class: css('_flex _gap2 _pt4') },
      Button({ variant: 'outline', class: css('_flex1') }, icon('message-circle'), 'Message'),
      link({ href: `/tenants/${tenant.id}`, class: css('_flex1') },
        Button({ variant: 'primary', class: css('_wfull') }, 'View Profile')
      )
    )
  );
}

