function TenantContactCard({ tenant }) {
  const { div, span, p } = tags;

  return div({ class: css('estate-card _p6 _tc') },
    Avatar({ src: tenant.avatar, alt: tenant.name, size: 'xl', fallback: tenant.name.charAt(0), class: css('_mb4') }),
    span({ class: css('_heading4 _block _mb1') }, tenant.name),
    p({ class: css('_textsm _fgmuted _mb4') }, `Unit ${tenant.unitNumber} at ${tenant.propertyName}`),
    div({ class: css('_flex _jcc _gap2') },
      Button({ variant: 'outline', size: 'icon', onclick: () => window.open(`tel:${tenant.phone}`) }, icon('phone')),
      Button({ variant: 'outline', size: 'icon', onclick: () => window.open(`mailto:${tenant.email}`) }, icon('mail')),
      Button({ variant: 'outline', size: 'icon', onclick: () => window.open(`sms:${tenant.phone}`) }, icon('message-circle'))
    )
  );
}

