function TenantSelfCard({ tenant }) {
  const { div, span, p, h2 } = tags;

  return div({ class: css('estate-card _p6') },
    div({ class: css('_flex _aic _gap4 _mb4') },
      div({ class: css('_relative') },
        Avatar({ src: tenant.avatar, alt: tenant.name, size: 'xl', fallback: tenant.name.charAt(0) }),
        Button({ variant: 'outline', size: 'icon', class: css('_absolute _bottom0 _right0 _bgSurface') }, icon('camera', { size: '14' }))
      ),
      div({},
        h2({ class: css('_heading4 _mb1') }, tenant.name),
        p({ class: css('_textsm _fgmuted') }, tenant.email),
        p({ class: css('_textsm _fgmuted') }, tenant.phone)
      )
    ),
    div({ class: css('_pt4 _borderT') },
      span({ class: css('_textxs _fgmuted _block _mb2') }, 'Your Residence'),
      p({ class: css('_font500') }, `${tenant.propertyName} - Unit ${tenant.unitNumber}`),
      p({ class: css('_textsm _fgmuted') }, tenant.propertyAddress)
    ),
    div({ class: css('_flex _jce _pt4') },
      Button({ variant: 'outline' }, icon('edit'), 'Edit Profile')
    )
  );
